import { useState, useCallback, useMemo, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Heart, Star, Sparkles, Plane, MapPin, CalendarDays, X, Plus, Minus, Check, Package } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { MOCK_SCENES, MOCK_OUTFITS } from '@/data/outfit';
import { MOCK_CLOTHING_ITEMS } from '@/data/clothing';
import type { IOutfit, IFavoriteOutfit } from '@/types/outfit';
import type { IClothingItem } from '@/types/clothing';

function getFavorites(): IFavoriteOutfit[] {
  try {
    return JSON.parse(localStorage.getItem('ootd_favorites') || '[]');
  } catch {
    return [];
  }
}

function saveFavorites(favs: IFavoriteOutfit[]) {
  localStorage.setItem('ootd_favorites', JSON.stringify(favs));
}

const sceneIcons: Record<string, string> = {
  Briefcase: '💼',
  Heart: '💕',
  Dumbbell: '🏋️',
  Plane: '✈️',
  FileText: '📋',
  PartyPopper: '🎉',
};

// ─── 旅行行程标签 ────────────────────────────────────────────────────
const TRIP_TAGS = ['海边', '商务', '运动', '逛街', '晚宴', '户外', '文艺', '休闲'] as const;

// ─── 旅行打包结果类型 ────────────────────────────────────────────────
interface IPackResult {
  tops: IClothingItem[];
  bottoms: IClothingItem[];
  outers: IClothingItem[];
  shoes: IClothingItem[];
  accessories: IClothingItem[];
}

export default function OutfitRecommendPage() {
  const [activeScene, setActiveScene] = useState(MOCK_SCENES[0].id);
  const [favorites, setFavorites] = useState<IFavoriteOutfit[]>(getFavorites);

  // ─── 旅行打包助手状态 ──────────────────────────────────────────────
  const [packOpen, setPackOpen] = useState(false);
  const [destination, setDestination] = useState('三亚');
  const [days, setDays] = useState(5);
  const [selectedTripTags, setSelectedTripTags] = useState<string[]>(['海边', '休闲']);
  const [packResult, setPackResult] = useState<IPackResult | null>(null);
  const [packGenerating, setPackGenerating] = useState(false);

  const sceneOutfits = useMemo(
    () => MOCK_OUTFITS.filter((o) => o.scene === activeScene),
    [activeScene]
  );

  const isFavorited = useCallback(
    (outfitId: number) => favorites.some((f) => f.id === outfitId),
    [favorites]
  );

  const handleToggleFavorite = useCallback(
    (outfit: IOutfit) => {
      const now = new Date();
      const dateStr = `${now.getFullYear()}/${now.getMonth() + 1}/${now.getDate()}`;

      setFavorites((prev) => {
        const exists = prev.find((f) => f.id === outfit.id);
        let next: IFavoriteOutfit[];
        if (exists) {
          next = prev.filter((f) => f.id !== outfit.id);
          toast.success('已取消收藏');
        } else {
          next = [
            {
              id: outfit.id,
              title: outfit.title,
              items: outfit.items.map((i) => i.name),
              date: dateStr,
              score: outfit.score,
            },
            ...prev,
          ];
          toast.success('已收藏穿搭');
        }
        saveFavorites(next);
        return next;
      });
    },
    []
  );

  // ─── 旅行打包逻辑 ──────────────────────────────────────────────────
  const handleToggleTripTag = useCallback((tag: string) => {
    setSelectedTripTags((prev) =>
      prev.includes(tag) ? prev.filter((t) => t !== tag) : [...prev, tag]
    );
  }, []);

  const handleGeneratePack = useCallback(async () => {
    setPackGenerating(true);
    await new Promise((r) => setTimeout(r, 1000));

    // 从衣橱中按规则选取衣物
    const allItems = [...MOCK_CLOTHING_ITEMS];
    const shuffled = allItems.sort(() => Math.random() - 0.5);

    const tops = shuffled.filter((i) => i.category === 'top').slice(0, Math.min(days, 4));
    const bottoms = shuffled.filter((i) => i.category === 'bottom').slice(0, Math.ceil(days / 2));
    const outers = shuffled.filter((i) => i.category === 'outer').slice(0, Math.min(Math.ceil(days / 3), 2));
    const shoes = shuffled.filter((i) => i.category === 'shoe').slice(0, Math.min(Math.ceil(days / 3), 2));
    const accessories = shuffled.filter((i) => i.category === 'accessory' || i.category === 'bag').slice(0, Math.min(Math.ceil(days / 2), 3));

    setPackResult({ tops, bottoms, outers, shoes, accessories });
    setPackGenerating(false);
    toast.success('打包清单已生成 ✈️');
  }, [days]);

  const handleSavePack = useCallback(() => {
    if (!packResult) return;
    const allNames = [
      ...packResult.tops.map((i) => i.name),
      ...packResult.bottoms.map((i) => i.name),
      ...packResult.outers.map((i) => i.name),
      ...packResult.shoes.map((i) => i.name),
      ...packResult.accessories.map((i) => i.name),
    ];
    const favs = getFavorites();
    const newFav: IFavoriteOutfit = {
      id: Date.now(),
      title: `${destination} ${days}日旅行清单`,
      items: allNames,
      date: new Date().toISOString().slice(0, 10),
      score: 95,
    };
    saveFavorites([newFav, ...favs]);
    setFavorites((prev) => [newFav, ...prev]);
    toast.success('旅行清单已加入收藏 💾');
  }, [packResult, destination, days]);

  const handleResetPack = useCallback(() => {
    setPackResult(null);
    setDestination('三亚');
    setDays(5);
    setSelectedTripTags(['海边', '休闲']);
  }, []);

  const totalPackItems = packResult
    ? packResult.tops.length +
      packResult.bottoms.length +
      packResult.outers.length +
      packResult.shoes.length +
      packResult.accessories.length
    : 0;

  return (
    <div className="min-h-screen bg-background">
      <main className="space-y-8">
        {/* 页面标题 */}
        <section className="w-full pt-8 pb-2">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <div className="flex items-center gap-2.5">
              <div className="flex size-9 items-center justify-center rounded-xl bg-primary/10">
                <Sparkles className="size-5 text-primary" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-foreground">穿搭推荐</h1>
                <p className="text-sm text-muted-foreground">根据场景，为你智能搭配</p>
              </div>
            </div>
          </div>
        </section>

        {/* 旅行打包助手入口卡片 */}
        <section className="w-full">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <motion.button
              type="button"
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
              whileHover={{ y: -2 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => setPackOpen(true)}
              className="w-full text-left"
            >
              <Card className="overflow-hidden border-border/50 shadow-sm hover:shadow-md transition-shadow duration-300 bg-gradient-to-r from-primary/5 via-card to-sky-50/50">
                <CardContent className="p-5">
                  <div className="flex items-center gap-4">
                    <div className="flex size-12 shrink-0 items-center justify-center rounded-xl bg-primary/10">
                      <Plane className="size-6 text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <h3 className="text-base font-semibold text-foreground">
                        旅行打包助手 ✈️
                      </h3>
                      <p className="text-sm text-muted-foreground mt-0.5">
                        输入行程，一键生成穿搭清单
                      </p>
                    </div>
                    <div className="flex size-8 shrink-0 items-center justify-center rounded-full bg-primary/10">
                      <Package className="size-4 text-primary" />
                    </div>
                  </div>
                </CardContent>
              </Card>
            </motion.button>
          </div>
        </section>

        {/* 场景选择 */}
        <section className="w-full py-2">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-none">
              {MOCK_SCENES.map((scene, i) => {
                const isActive = activeScene === scene.id;
                return (
                  <motion.button
                    key={scene.id}
                    type="button"
                    initial={{ opacity: 0, y: 12 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.4, delay: i * 0.06 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => setActiveScene(scene.id)}
                    className={`flex shrink-0 flex-col items-center gap-1.5 rounded-2xl px-5 py-3.5 transition-all duration-200 border min-w-[88px] ${
                      isActive
                        ? 'bg-primary text-primary-foreground border-primary shadow-md'
                        : 'bg-card text-foreground border-border/60 hover:border-primary/40 hover:shadow-sm'
                    }`}
                  >
                    <span className="text-2xl leading-none">
                      {sceneIcons[scene.icon] ?? '👔'}
                    </span>
                    <span className="text-sm font-semibold">{scene.name}</span>
                  </motion.button>
                );
              })}
            </div>
          </div>
        </section>

        {/* 穿搭方案列表 */}
        <section className="w-full py-2 pb-24">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <AnimatePresence mode="wait">
              <motion.div
                key={activeScene}
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }}
                transition={{ duration: 0.35 }}
                className="space-y-5"
              >
                {sceneOutfits.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
                    <span className="text-5xl mb-4">👔</span>
                    <p className="text-sm">该场景暂无推荐方案</p>
                  </div>
                ) : (
                  sceneOutfits.map((outfit, idx) => (
                    <OutfitCard
                      key={outfit.id}
                      outfit={outfit}
                      index={idx}
                      isFavorited={isFavorited(outfit.id)}
                      onToggleFavorite={() => handleToggleFavorite(outfit)}
                    />
                  ))
                )}
              </motion.div>
            </AnimatePresence>
          </div>
        </section>
      </main>

      {/* ─── 旅行打包助手弹窗 ────────────────────────────────────────── */}
      <Dialog open={packOpen} onOpenChange={setPackOpen}>
        <DialogContent className="max-w-md gap-0 p-0 overflow-hidden rounded-2xl max-h-[90vh] flex flex-col">
          <DialogHeader className="px-5 pt-5 pb-2 shrink-0">
            <div className="flex items-center justify-between">
              <DialogTitle className="text-lg font-bold flex items-center gap-2">
                <Plane className="size-5 text-primary" />
                旅行打包助手
              </DialogTitle>
              <Button
                size="icon"
                variant="ghost"
                className="h-8 w-8 rounded-full"
                onClick={() => {
                  setPackOpen(false);
                  handleResetPack();
                }}
              >
                <X className="size-4" />
              </Button>
            </div>
          </DialogHeader>

          <div className="flex-1 overflow-y-auto px-5 py-3 space-y-5">
            {/* 目的地输入 */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground flex items-center gap-1.5">
                <MapPin className="size-3.5 text-primary" />
                目的地
              </label>
              <Input
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
                placeholder="输入目的地城市"
                className="h-10 rounded-xl"
              />
            </div>

            {/* 天数选择 */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground flex items-center gap-1.5">
                <CalendarDays className="size-3.5 text-primary" />
                行程天数
              </label>
              <div className="flex items-center gap-3">
                <Button
                  type="button"
                  size="icon"
                  variant="outline"
                  className="h-9 w-9 rounded-full"
                  onClick={() => setDays((d) => Math.max(1, d - 1))}
                  disabled={days <= 1}
                >
                  <Minus className="size-3.5" />
                </Button>
                <span className="text-2xl font-bold tabular-nums text-foreground min-w-[2ch] text-center">
                  {days}
                </span>
                <Button
                  type="button"
                  size="icon"
                  variant="outline"
                  className="h-9 w-9 rounded-full"
                  onClick={() => setDays((d) => Math.min(14, d + 1))}
                  disabled={days >= 14}
                >
                  <Plus className="size-3.5" />
                </Button>
                <span className="text-sm text-muted-foreground">天</span>
              </div>
            </div>

            {/* 行程标签多选 */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">
                行程类型（可多选）
              </label>
              <div className="flex flex-wrap gap-2">
                {TRIP_TAGS.map((tag) => {
                  const isActive = selectedTripTags.includes(tag);
                  return (
                    <button
                      key={tag}
                      type="button"
                      onClick={() => handleToggleTripTag(tag)}
                      className={`inline-flex items-center rounded-full px-3.5 py-1.5 text-sm font-medium transition-all duration-200 border ${
                        isActive
                          ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                          : 'bg-card text-foreground border-border/60 hover:border-primary/40 hover:text-primary'
                      }`}
                    >
                      {tag}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* 生成按钮 */}
            {!packResult && (
              <Button
                onClick={handleGeneratePack}
                disabled={packGenerating || !destination.trim()}
                className="w-full gap-2 rounded-xl h-11"
              >
                {packGenerating ? (
                  <>
                    <span className="size-4 animate-spin rounded-full border-2 border-primary-foreground border-t-transparent" />
                    生成中...
                  </>
                ) : (
                  <>
                    <Package className="size-4" />
                    生成打包清单
                  </>
                )}
              </Button>
            )}

            {/* 打包结果 */}
            <AnimatePresence>
              {packResult && (
                <motion.div
                  initial={{ opacity: 0, y: 16 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                  className="space-y-4"
                >
                  {/* 结果摘要 */}
                  <div className="rounded-xl bg-gradient-to-br from-primary/8 to-sky-50/50 border border-primary/20 p-4">
                    <div className="flex items-center gap-2 mb-2">
                      <Check className="size-4 text-primary" />
                      <span className="text-sm font-semibold text-foreground">
                        {destination} · {days} 天行程
                      </span>
                    </div>
                    <div className="grid grid-cols-3 gap-2 text-center">
                      <div className="rounded-lg bg-card/80 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{packResult.tops.length}</div>
                        <div className="text-[10px] text-muted-foreground">上装</div>
                      </div>
                      <div className="rounded-lg bg-card/80 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{packResult.bottoms.length}</div>
                        <div className="text-[10px] text-muted-foreground">下装</div>
                      </div>
                      <div className="rounded-lg bg-card/80 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{packResult.outers.length}</div>
                        <div className="text-[10px] text-muted-foreground">外套</div>
                      </div>
                      <div className="rounded-lg bg-card/80 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{packResult.shoes.length}</div>
                        <div className="text-[10px] text-muted-foreground">鞋履</div>
                      </div>
                      <div className="rounded-lg bg-card/80 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{packResult.accessories.length}</div>
                        <div className="text-[10px] text-muted-foreground">配饰</div>
                      </div>
                      <div className="rounded-lg bg-primary/10 py-2">
                        <div className="text-lg font-bold text-primary tabular-nums">{totalPackItems}</div>
                        <div className="text-[10px] text-muted-foreground">总计</div>
                      </div>
                    </div>
                  </div>

                  {/* 衣物明细 */}
                  <div className="space-y-3">
                    {packResult.tops.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-muted-foreground mb-1.5">上装</h4>
                        <div className="flex flex-wrap gap-1.5">
                          {packResult.tops.map((item) => (
                            <Badge key={item.id} variant="outline" className="text-xs font-normal bg-muted/50">
                              {item.name}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                    {packResult.bottoms.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-muted-foreground mb-1.5">下装</h4>
                        <div className="flex flex-wrap gap-1.5">
                          {packResult.bottoms.map((item) => (
                            <Badge key={item.id} variant="outline" className="text-xs font-normal bg-muted/50">
                              {item.name}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                    {packResult.outers.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-muted-foreground mb-1.5">外套</h4>
                        <div className="flex flex-wrap gap-1.5">
                          {packResult.outers.map((item) => (
                            <Badge key={item.id} variant="outline" className="text-xs font-normal bg-muted/50">
                              {item.name}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                    {packResult.shoes.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-muted-foreground mb-1.5">鞋履</h4>
                        <div className="flex flex-wrap gap-1.5">
                          {packResult.shoes.map((item) => (
                            <Badge key={item.id} variant="outline" className="text-xs font-normal bg-muted/50">
                              {item.name}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                    {packResult.accessories.length > 0 && (
                      <div>
                        <h4 className="text-xs font-semibold text-muted-foreground mb-1.5">配饰/包包</h4>
                        <div className="flex flex-wrap gap-1.5">
                          {packResult.accessories.map((item) => (
                            <Badge key={item.id} variant="outline" className="text-xs font-normal bg-muted/50">
                              {item.name}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>

                  {/* 操作按钮 */}
                  <div className="flex gap-2 pt-1">
                    <Button
                      variant="outline"
                      size="sm"
                      className="flex-1 rounded-xl"
                      onClick={handleResetPack}
                    >
                      重新生成
                    </Button>
                    <Button
                      size="sm"
                      className="flex-1 rounded-xl gap-1.5"
                      onClick={handleSavePack}
                    >
                      <Heart className="size-3.5" />
                      一键加入收藏
                    </Button>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

/* ========== 穿搭卡片子组件 ========== */

interface OutfitCardProps {
  outfit: IOutfit;
  index: number;
  isFavorited: boolean;
  onToggleFavorite: () => void;
}

const OutfitCard = memo(function OutfitCard({
  outfit,
  index,
  isFavorited,
  onToggleFavorite,
}: OutfitCardProps) {
  const scoreColor =
    outfit.score >= 95
      ? 'text-primary'
      : outfit.score >= 90
        ? 'text-chart-2'
        : 'text-chart-3';

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.45, delay: index * 0.08 }}
    >
      <Card className="overflow-hidden border-border/50 shadow-sm hover:shadow-md transition-shadow duration-300">
        {/* 预览区 */}
        <div className="relative flex items-center justify-center bg-gradient-to-br from-primary/5 via-card to-secondary/10 py-10">
          <motion.span
            className="text-6xl select-none"
            whileHover={{ scale: 1.08 }}
            transition={{ duration: 0.25 }}
          >
            {outfit.previewEmoji}
          </motion.span>

          {/* 收藏按钮 */}
          <Button
            size="icon"
            variant="secondary"
            className="!absolute right-4 top-4 z-20 h-9 w-9 rounded-full shadow-sm"
            onClick={onToggleFavorite}
            aria-label={isFavorited ? '取消收藏' : '收藏'}
          >
            <Heart
              className={`size-4 transition-colors duration-200 ${
                isFavorited
                  ? 'fill-primary text-primary'
                  : 'text-muted-foreground'
              }`}
            />
          </Button>

          {/* 评分标签 */}
          <Badge
            variant="secondary"
            className="!absolute left-4 top-4 z-20 gap-1 px-2.5 py-1 text-xs font-semibold"
          >
            <Star className={`size-3 fill-current ${scoreColor}`} />
            <span className={scoreColor}>{outfit.score}% 适合</span>
          </Badge>
        </div>

        <CardHeader className="pb-2">
          <CardTitle className="text-base font-semibold">
            {outfit.title}
          </CardTitle>
          <p className="text-sm text-muted-foreground">{outfit.description}</p>
        </CardHeader>

        <CardContent className="pb-5">
          {/* 衣物列表 */}
          <div className="flex flex-wrap gap-1.5">
            {outfit.items.map((item, i) => (
              <Badge
                key={i}
                variant="outline"
                className="text-xs font-normal bg-muted/50 border-border/40"
              >
                {item.name}
              </Badge>
            ))}
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
});
