import { ActiveLink } from '@lark-apaas/client-toolkit-lite';
import { Outlet, useLocation } from 'react-router-dom';
import { Home, Shirt, Sparkles, Compass, User } from "lucide-react";

const NAV_ITEMS = [
  { path: "/", label: "首页", icon: Home },
  { path: "/wardrobe", label: "衣橱", icon: Shirt },
  { path: "/recommend", label: "推荐", icon: Sparkles },
  { path: "/discover", label: "发现", icon: Compass },
  { path: "/profile", label: "我的", icon: User },
];

export function Layout() {
  const { pathname } = useLocation();

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* 主内容区 */}
      <main className="flex-1 pb-16">
        <Outlet />
      </main>

      {/* 底部固定 TabBar */}
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-card/90 backdrop-blur-lg border-t border-border/60 safe-area-bottom">
        <div className="mx-auto flex h-16 max-w-lg items-center justify-around px-2">
          {NAV_ITEMS.map((item) => {
            const Icon = item.icon;
            const isActive =
              item.path === "/"
                ? pathname === "/"
                : pathname.startsWith(item.path);

            return (
              <ActiveLink
                key={item.path}
                to={item.path}
                end={item.path === "/"}
                className={({ isActive: linkActive }) =>
                  `flex flex-col items-center justify-center gap-0.5 min-w-0 px-2 py-1 rounded-lg transition-colors duration-200 ${
                    linkActive
                      ? "text-primary"
                      : "text-muted-foreground hover:text-foreground"
                  }`
                }
              >
                <Icon
                  className={`size-5 shrink-0 transition-all duration-200 ${
                    isActive ? "stroke-[2.25px]" : "stroke-[1.75px]"
                  }`}
                />
                <span
                  className={`text-[10px] leading-none font-medium transition-all duration-200 ${
                    isActive ? "font-semibold" : ""
                  }`}
                >
                  {item.label}
                </span>
              </ActiveLink>
            );
          })}
        </div>
      </nav>
    </div>
  );
}
