// ─── localStorage helpers ────────────────────────────────────────────
function getFavorites(): IFavoriteOutfit[] {
  try { return JSON.parse(localStorage.getItem('ootd_favorites') || '[]'); }
  catch { return []; }
}
function saveFavorites(favs: IFavoriteOutfit[]) {
  localStorage.setItem('ootd_favorites', JSON.stringify(favs));
}

function getStylePrefs(): string[] {
  try { return JSON.parse(localStorage.getItem('ootd_style_prefs') || '["极简"]'); }
  catch { return ['极简']; }
}
function saveStylePrefs(prefs: string[]) {
  localStorage.setItem('ootd_style_prefs', JSON.stringify(prefs));
}

function getCheckIn(): string | null {
  return localStorage.getItem('ootd_checkin_date');
}
function setCheckIn(date: string) {
  localStorage.setItem('ootd_checkin_date', date);
}

