const todayDate = (() => {
  const d = new Date();
  const weekDays = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
  return `${d.getMonth() + 1} 月 ${d.getDate()} 日 · ${weekDays[d.getDay()]}`;
})();

