// ─── 今日打卡横幅 ────────────────────────────────────────────────────
const CheckInBanner = memo(function CheckInBanner() {
  const [checkedIn, setCheckedIn] = useState(() => getCheckIn() === todayKey);
  const [animating, setAnimating] = useState(false);

  const handleCheckIn = useCallback(() => {
    if (checkedIn) return;
    setAnimating(true);
    setTimeout(() => {
      setCheckedIn(true);
      setCheckIn(todayKey);
      setAnimating(false);
      toast.success('今日打卡成功！📸 穿搭记录已保存');
    }, 600);
  }, [checkedIn]);

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
      className="relative overflow-hidden rounded-2xl border border-border/50 bg-gradient-to-r from-primary/10 via-card to-emerald-50/50 shadow-sm"
    >
      <div className="flex items-center justify-between px-5 py-4">
        <div className="flex items-center gap-3 min-w-0">
          <motion.div
            animate={animating ? { scale: [1, 1.3, 1], rotate: [0, -10, 10, 0] } : {}}
            transition={{ duration: 0.6 }}
            className={cn(
              'flex size-11 shrink-0 items-center justify-center rounded-xl shadow-sm transition-colors duration-300',
              checkedIn ? 'bg-emerald-100 text-emerald-600' : 'bg-primary/10 text-primary',
            )}
          >
            {checkedIn ? (
              <CheckCircle2 className="size-5" />
            ) : (
              <Camera className="size-5" />
            )}
          </motion.div>
          <div className="min-w-0">
            <p className="text-sm font-semibold text-foreground">
              {checkedIn ? '今日已打卡 ✓' : '今日穿搭打卡'}
            </p>
            <p className="text-xs text-muted-foreground mt-0.5">
              {checkedIn ? '穿搭记录已保存，明天继续加油！' : '记录今日穿搭，分享你的风格'}
            </p>
          </div>
        </div>
        <AnimatePresence mode="wait">
          {checkedIn ? (
            <motion.div
              key="done"
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              exit={{ scale: 0 }}
              className="flex items-center gap-1.5 rounded-full bg-emerald-100 px-3.5 py-1.5 text-xs font-semibold text-emerald-700"
            >
              <CheckCircle2 className="size-3.5" />
              已打卡
            </motion.div>
          ) : (
            <motion.button
              key="btn"
              type="button"
              whileTap={{ scale: 0.93 }}
              onClick={handleCheckIn}
              disabled={animating}
              className="shrink-0 rounded-full bg-primary px-4 py-1.5 text-xs font-semibold text-primary-foreground shadow-sm transition-all duration-200 hover:bg-primary/90 disabled:opacity-60"
            >
              {animating ? '打卡中...' : '立即打卡'}
            </motion.button>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
});

