// ─── 主页面 ──────────────────────────────────────────────────────────
export default function HomePage() {
  const navigate = useNavigate();
  const [stylePrefs, setStylePrefs] = useState<string[]>(getStylePrefs);
  const [outfit, setOutfit] = useState<IOutfit>(defaultOutfit);
  const [isFavorited, setIsFavorited] = useState(() => {
    const favs = getFavorites();
    return favs.some((f) => f.title === defaultOutfit.title);
  });
  const [inputFlowOpen, setInputFlowOpen] = useState(false);

  const handleToggleStyle = useCallback((tag: string) => {
    setStylePrefs((prev) => {
      const next = prev.includes(tag) ? prev.filter((t) => t !== tag) : [...prev, tag];
      saveStylePrefs(next);
      return next;
    });
  }, []);

  const handleRefreshOutfit = useCallback(() => {
    const others = MOCK_OUTFITS.filter((o) => o.id !== outfit.id);
    const pick = others[Math.floor(Math.random() * others.length)] ?? MOCK_OUTFITS[0];
    setOutfit(pick);
    const favs = getFavorites();
    setIsFavorited(favs.some((f) => f.title === pick.title));
    toast.success('已为你换一套新穿搭 ✨');
  }, [outfit.id]);

  const handleFavorite = useCallback(() => {
    const favs = getFavorites();
    if (isFavorited) {
      const next = favs.filter((f) => f.title !== outfit.title);
      saveFavorites(next);
      setIsFavorited(false);
      toast.success('已取消收藏');
    } else {
      const newFav: IFavoriteOutfit = {
        id: Date.now(),
        title: outfit.title,
        items: outfit.items.map((i) => i.name),
        date: new Date().toISOString().slice(0, 10),
        score: outfit.score,
      };
      saveFavorites([newFav, ...favs]);
      setIsFavorited(true);
      toast.success('已收藏到我的穿搭 💾');
    }
  }, [isFavorited, outfit]);

  return (
    <div className="min-h-screen bg-background">
      <main className="space-y-5 md:space-y-6">
        {/* ── 顶部：Hero + 紧凑天气 ── */}
        <section className="w-full pt-6 pb-1">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <motion.div
              initial={{ opacity: 0, y: -12 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
              className="space-y-3"
            >
              <div className="flex items-end justify-between">
                <div>
                  <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight">
                    <span className="bg-gradient-to-r from-primary via-primary to-orange-400 bg-clip-text text-transparent">
                      OOTD
                    </span>
                  </h1>
                  <p className="text-sm text-muted-foreground mt-0.5">
                    每一天，穿出属于自己的风格
                  </p>
                </div>
              </div>
              <CompactWeather />
            </motion.div>
          </div>
        </section>

        {/* ── 一键录入大卡片 ── */}
        <section className="w-full">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <QuickAddBanner onOpenInput={() => setInputFlowOpen(true)} />
          </div>
        </section>

        {/* ── 今日穿搭推荐 ── */}
        <section className="w-full">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-base font-semibold text-foreground">今日推荐</h2>
              <span className="text-xs text-muted-foreground">{todayDate}</span>
            </div>
            <OutfitCard
              outfit={outfit}
              isFavorited={isFavorited}
              onRefresh={handleRefreshOutfit}
              onFavorite={handleFavorite}
            />
          </div>
        </section>

        {/* ── 风格偏好标签 ── */}
        <section className="w-full">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <StyleTagsBar
              tags={MOCK_STYLE_TAGS}
              selected={stylePrefs}
              onToggle={handleToggleStyle}
            />
          </div>
        </section>

        {/* ── 今日穿搭打卡横幅 ── */}
        <section className="w-full">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <CheckInBanner />
          </div>
        </section>

        {/* ── 社区热门穿搭（弱化） ── */}
        <section className="w-full pb-12">
          <div className="max-w-7xl mx-auto px-4 md:px-6">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-sm font-semibold text-muted-foreground">社区热门穿搭</h2>
              <button
                type="button"
                onClick={() => navigate('/discover')}
                className="flex items-center gap-1 text-xs text-primary font-medium hover:underline transition-colors"
              >
                查看更多
                <ArrowRight className="size-3" />
              </button>
            </div>
            <div className="flex gap-2.5 overflow-x-auto pb-2 scrollbar-none">
              {MOCK_COMMUNITY_POSTS.map((post, i) => (
                <CommunityPostCard key={post.id} post={post} index={i} />
              ))}
            </div>
          </div>
        </section>
      </main>

      {/* ── 衣物智能录入流程 ── */}
      <ClothingInputFlow
        open={inputFlowOpen}
        onClose={() => setInputFlowOpen(false)}
        onComplete={(item: IClothingItem) => {
          toast.success(`"${item.name}" 已加入衣橱`);
        }}
      />
    </div>
  );
}
