import { useState } from "react";
import { toast } from "sonner";
import { MOCK_CLOTHING_ITEMS } from "@/data/clothing";
import type { IClothingItem, ClothingCategory } from "@/types/clothing";
import WardrobeHeaderSection from "./WardrobeHeaderSection";
import WardrobeGridSection from "./WardrobeGridSection";
import ClothingInputFlow from "@/components/ClothingInputFlow";

export default function WardrobePage() {
  const [items, setItems] = useState<IClothingItem[]>(MOCK_CLOTHING_ITEMS);
  const [activeCategory, setActiveCategory] = useState<ClothingCategory | "all">("all");
  const [inputFlowOpen, setInputFlowOpen] = useState(false);

  const handleAddItem = (item: IClothingItem) => {
    setItems((prev) => [item, ...prev]);
  };

  return (
    <div className="space-y-6 px-4 md:px-6 py-6">
      <WardrobeHeaderSection items={items} onAddItem={handleAddItem} onOpenInputFlow={() => setInputFlowOpen(true)} />
      <WardrobeGridSection
        items={items}
        activeCategory={activeCategory}
        onCategoryChange={setActiveCategory}
      />

      <ClothingInputFlow
        open={inputFlowOpen}
        onClose={() => setInputFlowOpen(false)}
        onComplete={(item: IClothingItem) => {
          handleAddItem(item);
          toast.success(`"${item.name}" 已加入衣橱`);
        }}
      />
    </div>
  );
}
