import { useState, useMemo } from "react";
import { Plus, Upload, Shirt, Footprints, Gem, TrendingUp, Percent } from "lucide-react";
import { Button } from "@/components/ui/button";
import type { IClothingItem } from "@/types/clothing";

interface WardrobeHeaderSectionProps {
  items: IClothingItem[];
  onAddItem: (item: IClothingItem) => void;
  onOpenInputFlow: () => void;
}

export default function WardrobeHeaderSection({ items, onAddItem, onOpenInputFlow }: WardrobeHeaderSectionProps) {
  const [uploading, setUploading] = useState(false);

  const totalCount = items.length;
  const topCount = items.filter((i) => i.category === "top").length;
  const bottomCount = items.filter((i) => i.category === "bottom").length;
  const shoeCount = items.filter((i) => i.category === "shoe").length;
  const accessoryCount = items.filter(
    (i) => i.category === "accessory" || i.category === "bag"
  ).length;

  // 本月穿着次数（所有衣物穿着次数之和，模拟"本月"数据）
  const monthlyWearCount = useMemo(
    () => items.reduce((sum, item) => sum + Math.min(item.wearCount, 30), 0),
    [items]
  );

  // 衣橱利用率：有穿着记录的衣物数 / 总衣物数
  const utilizationRate = useMemo(() => {
    if (totalCount === 0) return 0;
    const wornCount = items.filter((i) => i.wearCount > 0).length;
    return Math.round((wornCount / totalCount) * 100);
  }, [items, totalCount]);

  const statCards = [
    { label: "全部", count: totalCount, icon: Shirt, color: "text-primary" },
    { label: "上装", count: topCount, icon: Shirt, color: "text-chart-2" },
    { label: "下装", count: bottomCount, icon: Footprints, color: "text-chart-3" },
    { label: "鞋履", count: shoeCount, icon: Footprints, color: "text-chart-4" },
    { label: "配饰", count: accessoryCount, icon: Gem, color: "text-chart-5" },
  ];

  const handleFileSelect = () => {
    onOpenInputFlow();
  };

  return (
    <div className="space-y-5">
      {/* 标题行 + 添加按钮 */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-foreground">
            我的衣橱
          </h1>
          <p className="mt-1 text-sm text-muted-foreground">
            管理你的全部单品，上传即自动分类
          </p>
        </div>
        <Button
          onClick={handleFileSelect}
          disabled={uploading}
          size="sm"
          className="shrink-0 gap-1.5 rounded-full px-5"
        >
          {uploading ? (
            <>
              <span className="size-4 animate-spin rounded-full border-2 border-primary-foreground border-t-transparent" />
              识别中...
            </>
          ) : (
            <>
              <Plus className="size-4" />
              添加衣物
            </>
          )}
        </Button>
      </div>

      {/* 上传区域 */}
      <button
        type="button"
        onClick={handleFileSelect}
        disabled={uploading}
        className="w-full rounded-xl border-2 border-dashed border-border/80 bg-muted/30 px-4 py-6 text-center transition-colors hover:border-primary/40 hover:bg-muted/50 disabled:opacity-60"
      >
        <div className="flex flex-col items-center gap-2">
          <div className="flex size-12 items-center justify-center rounded-full bg-primary/10">
            <Upload className="size-5 text-primary" />
          </div>
          <div>
            <p className="text-sm font-medium text-foreground">
              点击上传服装照片
            </p>
            <p className="mt-0.5 text-xs text-muted-foreground">
              支持 JPG / PNG，系统自动识别品类和季节
            </p>
          </div>
        </div>
      </button>

      {/* 统计卡片 */}
      <div className="grid grid-cols-5 gap-2">
        {statCards.map((stat) => {
          const Icon = stat.icon;
          return (
            <div
              key={stat.label}
              className="flex flex-col items-center gap-1 rounded-xl bg-card px-2 py-3 text-center shadow-xs transition-shadow hover:shadow-sm"
            >
              <Icon className={`size-4 ${stat.color}`} />
              <span className="text-lg font-bold tabular-nums leading-none text-foreground">
                {stat.count}
              </span>
              <span className="text-[10px] leading-none text-muted-foreground">
                {stat.label}
              </span>
            </div>
          );
        })}
      </div>

      {/* 本月穿着 + 衣橱利用率 */}
      <div className="grid grid-cols-2 gap-3">
        <div className="flex items-center gap-3 rounded-xl border border-border/60 bg-card px-4 py-3 shadow-xs">
          <div className="flex size-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
            <TrendingUp className="size-5 text-primary" />
          </div>
          <div className="min-w-0">
            <p className="text-xs text-muted-foreground">本月穿着</p>
            <p className="text-lg font-bold tabular-nums text-foreground">
              {monthlyWearCount} <span className="text-sm font-normal text-muted-foreground">次</span>
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 rounded-xl border border-border/60 bg-card px-4 py-3 shadow-xs">
          <div className="flex size-10 shrink-0 items-center justify-center rounded-lg bg-chart-2/15">
            <Percent className="size-5 text-chart-2" />
          </div>
          <div className="min-w-0">
            <p className="text-xs text-muted-foreground">衣橱利用率</p>
            <p className="text-lg font-bold tabular-nums text-foreground">
              {utilizationRate}<span className="text-sm font-normal text-muted-foreground">%</span>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
