// Tab1: 种草商城（保留原有功能）
// ═══════════════════════════════════════════════════════
function ShopTab() {
  const [keyword, setKeyword] = useState('');
  const [activeCategory, setActiveCategory] = useState<CategoryKey>('new');
  const [selectedProduct, setSelectedProduct] = useState<IProduct | null>(null);
  const [sheetOpen, setSheetOpen] = useState(false);

  const filteredProducts = useMemo(() => {
    let list = MOCK_PRODUCTS.filter((p) => p.category === activeCategory);
    if (keyword.trim()) {
      const kw = keyword.trim().toLowerCase();
      list = list.filter(
        (p) =>
          p.name.toLowerCase().includes(kw) ||
          p.merchant.toLowerCase().includes(kw) ||
          p.tags.some((t) => t.toLowerCase().includes(kw)),
      );
    }
    return list;
  }, [activeCategory, keyword]);

  const handleSearch = useCallback(
    (e: React.FormEvent) => {
      e.preventDefault();
      if (!keyword.trim()) return;
      toast.info(`搜索"${keyword.trim()}"的结果`);
    },
    [keyword],
  );

  const handleProductClick = useCallback((product: IProduct) => {
    setSelectedProduct(product);
    setSheetOpen(true);
  }, []);

  const handleBuy = useCallback((product: IProduct) => {
    toast.success(`已跳转至 ${product.merchant} 购买"${product.name}"`);
  }, []);

  const handleFavorite = useCallback((product: IProduct) => {
    toast.success(`已收藏"${product.name}"`);
  }, []);

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      transition={{ duration: 0.3 }}
      className="space-y-6"
    >
      {/* 搜索栏 */}
      <section className="w-full">
        <div className="max-w-7xl mx-auto px-4 md:px-6">
          <form onSubmit={handleSearch} className="relative w-full">
            <Search className="pointer-events-none absolute left-3.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              type="search"
              value={keyword}
              onChange={(e) => setKeyword(e.target.value)}
              placeholder="搜索品牌、品类或风格关键词"
              className="bg-card pl-10 pr-10 h-11 rounded-xl border-border/60 shadow-sm focus-visible:ring-primary/30"
            />
            {keyword && (
              <Button
                type="button"
                size="icon"
                variant="ghost"
                className="!absolute right-1.5 top-1/2 z-20 h-7 w-7 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                onClick={() => setKeyword('')}
                aria-label="清除"
              >
                <X className="size-3.5" />
              </Button>
            )}
          </form>
        </div>
      </section>

      {/* 分类标签栏 */}
      <section className="w-full">
        <div className="max-w-7xl mx-auto px-4 md:px-6">
          <div className="flex gap-2">
            {CATEGORY_TABS.map((tab) => {
              const Icon = tab.icon;
              const isActive = activeCategory === tab.key;
              return (
                <motion.button
                  key={tab.key}
                  type="button"
                  whileTap={{ scale: 0.96 }}
                  onClick={() => setActiveCategory(tab.key)}
                  className={`inline-flex items-center gap-1.5 rounded-full px-4 py-2 text-sm font-medium transition-all duration-200 border ${
                    isActive
                      ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                      : 'bg-card text-foreground border-border/60 hover:border-primary/40 hover:text-primary'
                  }`}
                >
                  <Icon className="size-3.5" />
                  {tab.label}
                </motion.button>
              );
            })}
          </div>
        </div>
      </section>

      {/* 商品卡片流 */}
      <section className="w-full pb-8">
        <div className="max-w-7xl mx-auto px-4 md:px-6">
          {filteredProducts.length === 0 ? (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="flex flex-col items-center justify-center py-20 text-center"
            >
              <ShoppingBag className="size-12 text-muted-foreground/40 mb-4" />
              <p className="text-sm text-muted-foreground">
                {keyword.trim()
                  ? `没有找到与"${keyword.trim()}"相关的商品`
                  : '暂无商品'}
              </p>
              {keyword.trim() && (
                <Button
                  variant="ghost"
                  size="sm"
                  className="mt-3"
                  onClick={() => setKeyword('')}
                >
                  清除搜索
                </Button>
              )}
            </motion.div>
          ) : (
            <div className="grid grid-cols-2 gap-4">
              <AnimatePresence mode="wait">
                {filteredProducts.map((product, i) => (
                  <motion.div
                    key={product.id}
                    layout
                    initial={{ opacity: 0, y: 16 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95 }}
                    transition={{ duration: 0.35, delay: i * 0.05, ease: [0.16, 1, 0.3, 1] }}
                    whileHover={{ y: -3, transition: { duration: 0.2 } }}
                  >
                    <Card
                      className="group cursor-pointer overflow-hidden border-border/50 shadow-sm hover:shadow-md transition-shadow duration-300"
                      onClick={() => handleProductClick(product)}
                    >
                      <div className="relative aspect-[3/4] overflow-hidden bg-muted/50">
                        {product.image ? (
                          <Image
                            src={product.image}
                            alt={product.name}
                            className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-105"
                          />
                        ) : (
                          <div className="flex h-full w-full items-center justify-center text-5xl text-muted-foreground/30">
                            👕
                          </div>
                        )}
                        <Badge
                          variant="secondary"
                          className="!absolute left-2 top-2 z-20 text-[10px] px-2 py-0.5"
                        >
                          {product.category === 'new' ? '新品' : product.category === 'hot' ? '热销' : '推荐'}
                        </Badge>
                        <Button
                          type="button"
                          size="icon"
                          variant="secondary"
                          className="!absolute right-2 top-2 z-20 h-7 w-7 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity duration-200"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleFavorite(product);
                          }}
                          aria-label="收藏"
                        >
                          <Heart className="size-3.5" />
                        </Button>
                      </div>
                      <CardContent className="p-3 space-y-1.5">
                        <h3 className="text-sm font-medium leading-snug line-clamp-2 text-foreground">
                          {product.name}
                        </h3>
                        <p className="text-xs text-muted-foreground truncate">{product.merchant}</p>
                        <div className="flex items-baseline gap-1.5 pt-0.5">
                          <span className="text-sm font-bold text-primary tabular-nums">¥{product.price}</span>
                          {product.originalPrice > product.price && (
                            <span className="text-xs text-muted-foreground/60 line-through tabular-nums">
                              ¥{product.originalPrice}
                            </span>
                          )}
                        </div>
                        <div className="flex flex-wrap gap-1 pt-1">
                          {product.tags.slice(0, 2).map((tag) => (
                            <span key={tag} className="inline-block rounded-md bg-muted px-1.5 py-0.5 text-[10px] text-muted-foreground">
                              {tag}
                            </span>
                          ))}
                        </div>
                      </CardContent>
                    </Card>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>
          )}
        </div>
      </section>

      {/* 商品详情 Sheet */}
      <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
        <SheetContent side="bottom" className="h-[85vh] rounded-t-2xl px-0">
          {selectedProduct && (
            <div className="flex flex-col h-full overflow-y-auto">
              <div className="relative aspect-square w-full overflow-hidden bg-muted/30">
                {selectedProduct.image ? (
                  <Image src={selectedProduct.image} alt={selectedProduct.name} className="h-full w-full object-cover" />
                ) : (
                  <div className="flex h-full w-full items-center justify-center text-7xl text-muted-foreground/30">👕</div>
                )}
              </div>
              <div className="flex-1 px-5 py-5 space-y-4">
                <SheetHeader className="text-left p-0">
                  <SheetTitle className="text-xl font-bold">{selectedProduct.name}</SheetTitle>
                  <SheetDescription className="text-sm text-muted-foreground mt-1">{selectedProduct.merchant}</SheetDescription>
                </SheetHeader>
                <div className="flex items-baseline gap-2">
                  <span className="text-2xl font-bold text-primary tabular-nums">¥{selectedProduct.price}</span>
                  {selectedProduct.originalPrice > selectedProduct.price && (
                    <span className="text-sm text-muted-foreground/60 line-through tabular-nums">¥{selectedProduct.originalPrice}</span>
                  )}
                  {selectedProduct.originalPrice > selectedProduct.price && (
                    <Badge variant="destructive" className="text-xs">省¥{selectedProduct.originalPrice - selectedProduct.price}</Badge>
                  )}
                </div>
                <p className="text-sm text-foreground/80 leading-relaxed">{selectedProduct.description}</p>
                <div className="flex flex-wrap gap-1.5">
                  {selectedProduct.tags.map((tag) => (
                    <Badge key={tag} variant="outline" className="text-xs">{tag}</Badge>
                  ))}
                </div>
                <div className="flex gap-3 pt-2">
                  <Button variant="outline" size="lg" className="flex-1 rounded-xl" onClick={() => handleFavorite(selectedProduct)}>
                    <Heart className="size-4 mr-2" />收藏
                  </Button>
                  <Button size="lg" className="flex-1 rounded-xl" onClick={() => handleBuy(selectedProduct)}>
                    <ShoppingBag className="size-4 mr-2" />去购买
                  </Button>
                </div>
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>
    </motion.div>
  );
}

