// Tab2: 穿搭社区（全新功能）
// ═══════════════════════════════════════════════════════
function CommunityTab() {
  const [activeFilter, setActiveFilter] = useState<CommunityFilterKey>('all');
  const [posts, setPosts] = useState<ICommunityPost[]>(MOCK_POSTS);
  const [selectedPost, setSelectedPost] = useState<ICommunityPost | null>(null);
  const [postDetailOpen, setPostDetailOpen] = useState(false);
  const [publishOpen, setPublishOpen] = useState(false);
  const [publishText, setPublishText] = useState('');

  const filteredPosts = useMemo(() => {
    if (activeFilter === 'all') return posts;
    if (activeFilter === 'school') return posts.filter((p) => p.user.school === '北京服装学院');
    if (activeFilter === 'best') return [...posts].sort((a, b) => b.likes - a.likes);
    return posts;
  }, [posts, activeFilter]);

  const handleLike = useCallback((postId: number, e: React.MouseEvent) => {
    e.stopPropagation();
    setPosts((prev) =>
      prev.map((p) => {
        if (p.id !== postId) return p;
        const wasLiked = p.liked;
        return { ...p, liked: !wasLiked, likes: wasLiked ? p.likes - 1 : p.likes + 1 };
      }),
    );
  }, []);

  const handlePostClick = useCallback((post: ICommunityPost) => {
    setSelectedPost(post);
    setPostDetailOpen(true);
  }, []);

  const handlePublish = useCallback(() => {
    if (!publishText.trim()) {
      toast.info('请写点什么吧');
      return;
    }
    const newPost: ICommunityPost = {
      id: Date.now(),
      user: { name: '我', avatar: '', school: '北京服装学院' },
      image: '',
      caption: publishText.trim(),
      tags: ['#OOTD'],
      likes: 0,
      comments: 0,
      time: '刚刚',
      liked: false,
    };
    setPosts((prev) => [newPost, ...prev]);
    setPublishText('');
    setPublishOpen(false);
    toast.success('发布成功！');
  }, [publishText]);

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      transition={{ duration: 0.3 }}
      className="space-y-5"
    >
      {/* 社区筛选标签 */}
      <section className="w-full">
        <div className="max-w-7xl mx-auto px-4 md:px-6">
          <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-none">
            {COMMUNITY_FILTERS.map((f) => {
              const isActive = activeFilter === f.key;
              return (
                <motion.button
                  key={f.key}
                  type="button"
                  whileTap={{ scale: 0.96 }}
                  onClick={() => setActiveFilter(f.key)}
                  className={`shrink-0 inline-flex items-center gap-1.5 rounded-full px-4 py-1.5 text-sm font-medium transition-all duration-200 border ${
                    isActive
                      ? 'bg-primary text-primary-foreground border-primary shadow-sm'
                      : 'bg-card text-foreground border-border/60 hover:border-primary/40 hover:text-primary'
                  }`}
                >
                  {f.key === 'all' && <Users className="size-3.5" />}
                  {f.key === 'school' && <School className="size-3.5" />}
                  {f.key === 'follow' && <Heart className="size-3.5" />}
                  {f.key === 'best' && <Flame className="size-3.5" />}
                  {f.label}
                </motion.button>
              );
            })}
          </div>
        </div>
      </section>

      {/* 帖子信息流 */}
      <section className="w-full pb-20">
        <div className="max-w-7xl mx-auto px-4 md:px-6">
          {filteredPosts.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
              <Users className="size-12 mb-3 opacity-30" />
              <p className="text-sm">暂无帖子</p>
            </div>
          ) : (
            <div className="space-y-4">
              {filteredPosts.map((post, i) => (
                <PostCard
                  key={post.id}
                  post={post}
                  index={i}
                  onLike={(e) => handleLike(post.id, e)}
                  onClick={() => handlePostClick(post)}
                />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* 右下角悬浮发布按钮 */}
      <motion.button
        type="button"
        whileHover={{ scale: 1.08 }}
        whileTap={{ scale: 0.92 }}
        onClick={() => setPublishOpen(true)}
        className="fixed bottom-20 right-5 z-40 flex size-14 items-center justify-center rounded-full bg-primary text-primary-foreground shadow-lg hover:shadow-xl transition-shadow"
      >
        <Plus className="size-6" />
      </motion.button>

      {/* 帖子详情弹窗 */}
      <Dialog open={postDetailOpen} onOpenChange={setPostDetailOpen}>
        <DialogContent className="max-w-md gap-0 p-0 overflow-hidden rounded-2xl max-h-[90vh] overflow-y-auto">
          {selectedPost && (
            <>
              {/* 帖子大图 */}
              <div className="relative aspect-[4/3] w-full bg-muted/30">
                {selectedPost.image ? (
                  <Image src={selectedPost.image} alt={selectedPost.caption} className="h-full w-full object-cover" />
                ) : (
                  <div className="flex h-full w-full items-center justify-center text-6xl text-muted-foreground/25">👕</div>
                )}
              </div>

              <div className="p-5 space-y-4">
                {/* 发布者信息 */}
                <div className="flex items-center gap-3">
                  <div className="flex size-10 shrink-0 items-center justify-center rounded-full bg-primary/10">
                    <Users className="size-5 text-primary" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-semibold text-foreground">{selectedPost.user.name}</span>
                      <span className="text-xs text-muted-foreground flex items-center gap-0.5">
                        <MapPin className="size-3" />
                        {selectedPost.user.school}
                      </span>
                    </div>
                    <p className="text-xs text-muted-foreground">{selectedPost.time}</p>
                  </div>
                </div>

                {/* 文案 */}
                <p className="text-sm text-foreground leading-relaxed">{selectedPost.caption}</p>

                {/* 标签 */}
                <div className="flex flex-wrap gap-1.5">
                  {selectedPost.tags.map((tag) => (
                    <Badge key={tag} variant="secondary" className="text-xs font-normal">{tag}</Badge>
                  ))}
                </div>

                {/* 互动栏 */}
                <div className="flex items-center gap-5 border-y border-border/40 py-3">
                  <button type="button" onClick={(e) => handleLike(selectedPost.id, e)} className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-primary transition-colors">
                    <Heart className={`size-4 transition-colors ${selectedPost.liked ? 'fill-primary text-primary' : ''}`} />
                    <span>{selectedPost.likes}</span>
                  </button>
                  <button type="button" className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors">
                    <MessageCircle className="size-4" />
                    <span>{selectedPost.comments}</span>
                  </button>
                  <button type="button" onClick={() => toast.success('已分享')} className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors">
                    <Share2 className="size-4" />
                    <span>分享</span>
                  </button>
                </div>

                {/* 评论区 */}
                <div className="space-y-3">
                  <h4 className="text-sm font-semibold text-foreground">评论 ({MOCK_COMMENTS.length})</h4>
                  {MOCK_COMMENTS.map((comment) => (
                    <div key={comment.id} className="flex gap-3">
                      <div className="flex size-8 shrink-0 items-center justify-center rounded-full bg-muted">
                        <Users className="size-4 text-muted-foreground" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-semibold text-foreground">{comment.user}</span>
                          <span className="text-[10px] text-muted-foreground">{comment.time}</span>
                        </div>
                        <p className="text-sm text-foreground/80 mt-0.5">{comment.text}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>

      {/* 发布弹窗 */}
      <Dialog open={publishOpen} onOpenChange={setPublishOpen}>
        <DialogContent className="max-w-md rounded-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <ImageIcon className="size-5 text-primary" />
              发布穿搭
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            {/* 选图区 */}
            <button
              type="button"
              onClick={() => toast.info('选择图片功能（演示）')}
              className="flex w-full flex-col items-center gap-2 rounded-xl border-2 border-dashed border-border/60 bg-muted/30 py-8 transition-colors hover:border-primary/40"
            >
              <ImageIcon className="size-8 text-muted-foreground" />
              <span className="text-sm text-muted-foreground">点击选择图片</span>
            </button>

            {/* 文案输入 */}
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-foreground">写点什么</label>
              <textarea
                value={publishText}
                onChange={(e) => setPublishText(e.target.value)}
                placeholder="分享你的穿搭心得..."
                rows={3}
                maxLength={200}
                className="w-full resize-none rounded-xl border border-border/60 bg-card px-4 py-3 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/30"
              />
              <p className="text-xs text-muted-foreground text-right">{publishText.length}/200</p>
            </div>

            {/* 发布按钮 */}
            <Button onClick={handlePublish} className="w-full gap-2 rounded-xl" size="lg">
              <Send className="size-4" />
              发布
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </motion.div>
  );
}

// ═══════════════════════════════════════════════════════
// 帖子卡片子组件
// ═══════════════════════════════════════════════════════
interface PostCardProps {
  post: ICommunityPost;
  index: number;
  onLike: (e: React.MouseEvent) => void;
  onClick: () => void;
}

function PostCard({ post, index, onLike, onClick }: PostCardProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, delay: index * 0.06, ease: [0.16, 1, 0.3, 1] }}
    >
      <Card
        className="cursor-pointer overflow-hidden border-border/50 shadow-sm hover:shadow-md transition-shadow duration-300"
        onClick={onClick}
      >
        {/* 发布者信息 */}
        <div className="flex items-center gap-3 px-4 pt-4 pb-2">
          <div className="flex size-9 shrink-0 items-center justify-center rounded-full bg-primary/10">
            <Users className="size-4.5 text-primary" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-sm font-semibold text-foreground">{post.user.name}</span>
              <span className="text-[11px] text-muted-foreground flex items-center gap-0.5">
                <MapPin className="size-2.5" />
                {post.user.school}
              </span>
            </div>
            <p className="text-xs text-muted-foreground">{post.time}</p>
          </div>
        </div>

        {/* 穿搭主图 */}
        <div className="relative aspect-[4/3] w-full overflow-hidden bg-muted/30">
          {post.image ? (
            <Image src={post.image} alt={post.caption} className="h-full w-full object-cover transition-transform duration-500 hover:scale-105" />
          ) : (
            <div className="flex h-full w-full items-center justify-center text-5xl text-muted-foreground/25">👕</div>
          )}
        </div>

        <CardContent className="p-4 space-y-3">
          {/* 文案 */}
          <p className="text-sm text-foreground leading-relaxed line-clamp-2">{post.caption}</p>

          {/* 标签 */}
          <div className="flex flex-wrap gap-1.5">
            {post.tags.map((tag) => (
              <Badge key={tag} variant="secondary" className="text-[10px] font-normal px-2 py-0">{tag}</Badge>
            ))}
          </div>

          {/* 互动栏 */}
          <div className="flex items-center gap-5 pt-1 border-t border-border/30">
            <button
              type="button"
              onClick={onLike}
              className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-primary transition-colors"
            >
              <motion.div
                whileTap={{ scale: 1.4 }}
                transition={{ duration: 0.15 }}
              >
                <Heart className={`size-4 transition-colors ${post.liked ? 'fill-primary text-primary' : ''}`} />
              </motion.div>
              <span>{post.likes}</span>
            </button>
            <button type="button" className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors">
              <MessageCircle className="size-4" />
              <span>{post.comments}</span>
            </button>
            <button
              type="button"
              onClick={(e) => { e.stopPropagation(); toast.success('已收藏'); }}
              className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors ml-auto"
            >
              <Star className="size-4" />
              <span>收藏</span>
            </button>
            <button
              type="button"
              onClick={(e) => { e.stopPropagation(); toast.success('已分享'); }}
              className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors"
            >
              <Share2 className="size-4" />
            </button>
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
}
