import { useState, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, ShoppingBag, Calendar, Hash, Palette, Sparkles, Tag, Store, Share2 } from "lucide-react";
import { Image } from "@/components/ui/image";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import type { IClothingItem, ClothingCategory } from "@/types/clothing";
import { CLOTHING_CATEGORIES } from "@/data/clothing";
import { MOCK_OUTFITS } from "@/data/outfit";
import type { IOutfit } from "@/types/outfit";

interface WardrobeGridSectionProps {
  items: IClothingItem[];
  activeCategory: ClothingCategory | "all";
  onCategoryChange: (cat: ClothingCategory | "all") => void;
}

const CATEGORY_LABEL_MAP: Record<ClothingCategory, string> = {
  top: "上装",
  bottom: "下装",
  outer: "外套",
  dress: "连衣裙",
  shoe: "鞋履",
  accessory: "配饰",
  bag: "包包",
};

const CATEGORY_BG_MAP: Record<ClothingCategory, string> = {
  top: "bg-blue-50",
  bottom: "bg-emerald-50",
  outer: "bg-amber-50",
  dress: "bg-pink-50",
  shoe: "bg-violet-50",
  accessory: "bg-rose-50",
  bag: "bg-teal-50",
};

const CATEGORY_TEXT_MAP: Record<ClothingCategory, string> = {
  top: "text-blue-700",
  bottom: "text-emerald-700",
  outer: "text-amber-700",
  dress: "text-pink-700",
  shoe: "text-violet-700",
  accessory: "text-rose-700",
  bag: "text-teal-700",
};

// ─── 一衣多穿 mock 数据 ──────────────────────────────────────────────
function getMultiWearOutfits(itemName: string): IOutfit[] {
  const lower = itemName.toLowerCase();
  return MOCK_OUTFITS.filter((o) =>
    o.items.some((i) => i.name.toLowerCase().includes(lower.slice(0, 4)))
  ).slice(0, 4);
}

// ─── 详情弹窗 Tab ────────────────────────────────────────────────────
type DetailTab = "detail" | "multiWear";

export default function WardrobeGridSection({
  items,
  activeCategory,
  onCategoryChange,
}: WardrobeGridSectionProps) {
  const [selectedItem, setSelectedItem] = useState<IClothingItem | null>(null);
  const [detailTab, setDetailTab] = useState<DetailTab>("detail");

  const filteredItems = useMemo(
    () =>
      activeCategory === "all"
        ? items
        : items.filter((i) => i.category === activeCategory),
    [items, activeCategory],
  );

  const handleOpenDetail = (item: IClothingItem) => {
    setSelectedItem(item);
    setDetailTab("detail");
  };

  const handleCloseDetail = () => {
    setSelectedItem(null);
    setDetailTab("detail");
  };

  const multiWearOutfits = selectedItem ? getMultiWearOutfits(selectedItem.name) : [];

  return (
    <section className="w-full">
      <div className="space-y-5">
        {/* 分类标签栏 */}
        <div className="flex items-center gap-2 overflow-x-auto pb-1 scrollbar-none">
          {CLOTHING_CATEGORIES.map((cat) => {
            const isActive = activeCategory === cat.key;
            return (
              <button
                key={cat.key}
                type="button"
                onClick={() => onCategoryChange(cat.key)}
                className={`shrink-0 rounded-full px-4 py-1.5 text-sm font-medium transition-all duration-200 ${
                  isActive
                    ? "bg-primary text-primary-foreground shadow-sm"
                    : "bg-secondary text-muted-foreground hover:bg-secondary/80 hover:text-foreground"
                }`}
              >
                {cat.label}
              </button>
            );
          })}
        </div>

        {/* 衣物网格 */}
        {filteredItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
            <ShoppingBag className="size-12 mb-3 opacity-30" />
            <p className="text-sm">暂无衣物</p>
            <p className="text-xs mt-1 opacity-60">点击上方"添加衣物"开始管理</p>
          </div>
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
            <AnimatePresence mode="popLayout">
              {filteredItems.map((item, i) => (
                <motion.button
                  key={item.id}
                  type="button"
                  layout
                  initial={{ opacity: 0, y: 12 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  transition={{
                    duration: 0.35,
                    delay: i * 0.04,
                    ease: [0.16, 1, 0.3, 1],
                  }}
                  whileHover={{ y: -3, scale: 1.02 }}
                  whileTap={{ scale: 0.97 }}
                  onClick={() => handleOpenDetail(item)}
                  className="group relative flex flex-col overflow-hidden rounded-xl border border-border/60 bg-card text-left shadow-sm transition-shadow duration-200 hover:shadow-md"
                >
                  {/* 图片区 */}
                  <div
                    className={`relative aspect-[3/4] w-full overflow-hidden ${
                      CATEGORY_BG_MAP[item.category] || "bg-muted"
                    }`}
                  >
                    {item.imageUrl ? (
                      <Image
                        src={item.imageUrl}
                        alt={item.name}
                        className="h-full w-full object-cover transition-transform duration-300 group-hover:scale-105"
                      />
                    ) : (
                      <div className="flex h-full w-full items-center justify-center">
                        <ShoppingBag className="size-10 text-muted-foreground/30" />
                      </div>
                    )}
                    {/* 分类角标 */}
                    <span
                      className={`absolute left-2 top-2 rounded-md px-1.5 py-0.5 text-[10px] font-semibold ${
                        CATEGORY_BG_MAP[item.category] || "bg-muted"
                      } ${CATEGORY_TEXT_MAP[item.category] || "text-foreground"}`}
                    >
                      {CATEGORY_LABEL_MAP[item.category]}
                    </span>
                  </div>

                  {/* 信息区 */}
                  <div className="flex flex-col gap-1.5 p-3">
                    <span className="truncate text-sm font-medium text-foreground">
                      {item.name}
                    </span>
                    <div className="flex items-center gap-1.5 flex-wrap">
                      <Badge variant="outline" className="text-[10px] h-5 px-1.5">
                        {item.color}
                      </Badge>
                      <span className="text-[10px] text-muted-foreground">
                        穿{item.wearCount}次
                      </span>
                    </div>
                  </div>
                </motion.button>
              ))}
            </AnimatePresence>
          </div>
        )}
      </div>

      {/* 衣物详情弹窗 — 含 Tab 切换 */}
      <Dialog
        open={!!selectedItem}
        onOpenChange={(open) => {
          if (!open) handleCloseDetail();
        }}
      >
        <DialogContent className="max-w-sm gap-0 p-0 overflow-hidden rounded-2xl max-h-[90vh] flex flex-col">
          {selectedItem && (
            <>
              {/* 大图 */}
              <div
                className={`relative aspect-[4/3] w-full shrink-0 ${
                  CATEGORY_BG_MAP[selectedItem.category] || "bg-muted"
                }`}
              >
                {selectedItem.imageUrl ? (
                  <Image
                    src={selectedItem.imageUrl}
                    alt={selectedItem.name}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full w-full items-center justify-center">
                    <ShoppingBag className="size-16 text-muted-foreground/25" />
                  </div>
                )}
                <Button
                  size="icon"
                  variant="secondary"
                  className="!absolute right-3 top-3 z-20 h-8 w-8 rounded-full shadow-sm"
                  onClick={handleCloseDetail}
                  aria-label="关闭"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              {/* Tab 切换栏 */}
              <div className="flex border-b border-border/60 shrink-0">
                <button
                  type="button"
                  onClick={() => setDetailTab("detail")}
                  className={`flex-1 py-3 text-sm font-medium transition-colors duration-200 relative ${
                    detailTab === "detail"
                      ? "text-primary"
                      : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  详情
                  {detailTab === "detail" && (
                    <motion.div
                      layoutId="detailTabIndicator"
                      className="absolute bottom-0 left-1/4 right-1/4 h-0.5 rounded-full bg-primary"
                      transition={{ duration: 0.25, ease: [0.16, 1, 0.3, 1] }}
                    />
                  )}
                </button>
                <button
                  type="button"
                  onClick={() => setDetailTab("multiWear")}
                  className={`flex-1 py-3 text-sm font-medium transition-colors duration-200 relative ${
                    detailTab === "multiWear"
                      ? "text-primary"
                      : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  <span className="inline-flex items-center gap-1">
                    <Sparkles className="size-3.5" />
                    一衣多穿
                  </span>
                  {detailTab === "multiWear" && (
                    <motion.div
                      layoutId="detailTabIndicator"
                      className="absolute bottom-0 left-1/4 right-1/4 h-0.5 rounded-full bg-primary"
                      transition={{ duration: 0.25, ease: [0.16, 1, 0.3, 1] }}
                    />
                  )}
                </button>
              </div>

              {/* Tab 内容区 — 可滚动 */}
              <div className="flex-1 overflow-y-auto">
                <AnimatePresence mode="wait">
                  {detailTab === "detail" ? (
                    <motion.div
                      key="detail"
                      initial={{ opacity: 0, x: -12 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -12 }}
                      transition={{ duration: 0.2 }}
                      className="p-5 space-y-4"
                    >
                      <DialogHeader className="p-0">
                        <DialogTitle className="text-lg font-semibold">
                          {selectedItem.name}
                        </DialogTitle>
                      </DialogHeader>

                      {/* 标签行 */}
                      <div className="flex flex-wrap gap-2">
                        <Badge variant="secondary" className="text-xs">
                          {CATEGORY_LABEL_MAP[selectedItem.category]}
                        </Badge>
                        <Badge variant="outline" className="text-xs">
                          {selectedItem.color}
                        </Badge>
                        <Badge variant="outline" className="text-xs">
                          {selectedItem.style}
                        </Badge>
                      </div>

                      {/* 详情网格 */}
                      <div className="grid grid-cols-2 gap-3 text-sm">
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Palette className="size-4 shrink-0" />
                          <span>材质</span>
                        </div>
                        <div className="text-foreground font-medium">
                          {selectedItem.material}
                        </div>

                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Calendar className="size-4 shrink-0" />
                          <span>购买时间</span>
                        </div>
                        <div className="text-foreground font-medium">
                          {selectedItem.purchaseDate}
                        </div>

                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Hash className="size-4 shrink-0" />
                          <span>穿着次数</span>
                        </div>
                        <div className="text-foreground font-medium">
                          {selectedItem.wearCount} 次
                        </div>

                        <div className="flex items-center gap-2 text-muted-foreground">
                          <ShoppingBag className="size-4 shrink-0" />
                          <span>品牌</span>
                        </div>
                        <div className="text-foreground font-medium">
                          {selectedItem.brand}
                        </div>
                      </div>

                      {/* 季节标签 */}
                      <div className="space-y-1.5">
                        <span className="text-xs text-muted-foreground">适用季节</span>
                        <div className="flex gap-1.5">
                          {selectedItem.season.map((s) => {
                            const label =
                              s === "spring"
                                ? "春"
                                : s === "summer"
                                  ? "夏"
                                  : s === "autumn"
                                    ? "秋"
                                    : "冬";
                            return (
                              <Badge
                                key={s}
                                variant="secondary"
                                className="text-[10px] h-5"
                              >
                                {label}
                              </Badge>
                            );
                          })}
                        </div>
                      </div>

                      {/* 价格 */}
                      <div className="flex items-center justify-between border-t border-border/60 pt-3">
                        <span className="text-sm text-muted-foreground">购入价格</span>
                        <span className="text-lg font-bold text-primary">
                          ¥{selectedItem.price}
                        </span>
                      </div>

                      {/* 底部操作按钮 */}
                      <div className="flex gap-2 pt-2">
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1 gap-1.5 rounded-xl"
                          onClick={() => toast.info("已发布到二手闲置市场，等待买家联系")}
                        >
                          <Store className="size-3.5" />
                          挂到二手闲置
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1 gap-1.5 rounded-xl"
                          onClick={() => toast.success("已加入共享衣橱，好友可见")}
                        >
                          <Share2 className="size-3.5" />
                          加入共享衣橱
                        </Button>
                      </div>
                    </motion.div>
                  ) : (
                    <motion.div
                      key="multiWear"
                      initial={{ opacity: 0, x: 12 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: 12 }}
                      transition={{ duration: 0.2 }}
                      className="p-5 space-y-4"
                    >
                      <DialogHeader className="p-0">
                        <DialogTitle className="text-lg font-semibold flex items-center gap-2">
                          <Sparkles className="size-5 text-primary" />
                          一衣多穿
                        </DialogTitle>
                        <p className="text-sm text-muted-foreground mt-1">
                          看看"{selectedItem.name}"的多种搭配灵感
                        </p>
                      </DialogHeader>

                      {multiWearOutfits.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
                          <Tag className="size-10 mb-3 opacity-30" />
                          <p className="text-sm">暂无搭配方案</p>
                          <p className="text-xs mt-1 opacity-60">试试其他衣物</p>
                        </div>
                      ) : (
                        <div className="space-y-3">
                          {multiWearOutfits.map((outfit, idx) => (
                            <motion.div
                              key={outfit.id}
                              initial={{ opacity: 0, y: 12 }}
                              animate={{ opacity: 1, y: 0 }}
                              transition={{ duration: 0.35, delay: idx * 0.08 }}
                              className="rounded-xl border border-border/60 bg-card p-4 shadow-sm hover:shadow-md transition-shadow duration-200"
                            >
                              {/* 穿搭标题 + 评分 */}
                              <div className="flex items-center justify-between mb-3">
                                <h4 className="text-sm font-semibold text-foreground">
                                  {outfit.title}
                                </h4>
                                <Badge variant="secondary" className="text-xs gap-1">
                                  <Sparkles className="size-3" />
                                  {outfit.score}%
                                </Badge>
                              </div>

                              {/* 预览 + 衣物列表 */}
                              <div className="flex items-center gap-3">
                                <div className="flex size-14 shrink-0 items-center justify-center rounded-xl bg-gradient-to-br from-primary/5 to-secondary/20 text-2xl">
                                  {outfit.previewEmoji}
                                </div>
                                <div className="flex-1 min-w-0">
                                  <p className="text-xs text-muted-foreground mb-1.5">
                                    {outfit.description}
                                  </p>
                                  <div className="flex flex-wrap gap-1">
                                    {outfit.items.slice(0, 4).map((oi, j) => (
                                      <Badge
                                        key={j}
                                        variant="outline"
                                        className="text-[10px] h-5 px-1.5 font-normal"
                                      >
                                        {oi.name}
                                      </Badge>
                                    ))}
                                  </div>
                                </div>
                              </div>

                              {/* 场景标签 */}
                              <div className="flex items-center gap-1.5 mt-3 pt-3 border-t border-border/40">
                                <Tag className="size-3 text-muted-foreground" />
                                <span className="text-xs text-muted-foreground">
                                  适合：
                                </span>
                                <Badge variant="secondary" className="text-[10px] h-5">
                                  {outfit.scene === "commute"
                                    ? "通勤"
                                    : outfit.scene === "date"
                                      ? "约会"
                                      : outfit.scene === "sport"
                                        ? "运动"
                                        : outfit.scene === "travel"
                                          ? "旅行"
                                          : outfit.scene === "interview"
                                            ? "面试"
                                            : outfit.scene === "party"
                                              ? "聚会"
                                              : outfit.scene}
                                </Badge>
                              </div>
                            </motion.div>
                          ))}
                        </div>
                      )}

                      {/* 底部操作按钮 */}
                      <div className="flex gap-2 pt-2">
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1 gap-1.5 rounded-xl"
                          onClick={() => toast.info("已发布到二手闲置市场，等待买家联系")}
                        >
                          <Store className="size-3.5" />
                          挂到二手闲置
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1 gap-1.5 rounded-xl"
                          onClick={() => toast.success("已加入共享衣橱，好友可见")}
                        >
                          <Share2 className="size-3.5" />
                          加入共享衣橱
                        </Button>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </section>
  );
}
